import sys

class Solution:
    def smallestCity(self, cities: list[str]) -> str:
        city_neighbors = {}
        i = 0
        while i < len(cities):
            city = cities[i]
            i += 1
            num_neighbors = int(cities[i])
            i += 1
            neighbors = cities[i:i + num_neighbors]
            i += num_neighbors
            city_neighbors[city] = num_neighbors
        min_neighbors = min(city_neighbors.values())
        smallest_cities = [city for city, neighbors in city_neighbors.items() if neighbors == min_neighbors]
        return min(smallest_cities)

