#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string smallestCity(vector<string>& cities) {
        unordered_map<string, int> city_neighbors;
        int i = 0;
        while (i < cities.size()) {
            string city = cities[i++];
            int num_neighbors = stoi(cities[i++]);
            city_neighbors[city] = num_neighbors;
            i += num_neighbors;
        }
        int min_neighbors = INT_MAX;
        string smallest_city;
        for (const auto& pair : city_neighbors) {
            if (pair.second < min_neighbors) {
                min_neighbors = pair.second;
                smallest_city = pair.first;
            } else if (pair.second == min_neighbors) {
                smallest_city = min(smallest_city, pair.first);
            }
        }
        return smallest_city;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int num_cities;
    cin >> num_cities;
    vector<string> cities;
    for (int i = 0; i < num_cities; i++) {
        string city;
        cin >> city;
        cities.push_back(city);
        int num_neighbors;
        cin >> num_neighbors;
        cities.push_back(to_string(num_neighbors));
        for (int j = 0; j < num_neighbors; j++) {
            string neighbor;
            cin >> neighbor;
            cities.push_back(neighbor);
        }
    }
    Solution sol;
    string ans = sol.smallestCity(cities);
    cout << ans << '\n';
    return 0;
}
